@Entity
@Table(name = "users", indexes = {
    @Index(name = "idx_users_email", columnList = "email", unique = true)
})
@Getter @Setter @NoArgsConstructor @Builder
public class User extends BaseEntity {
    @Column(nullable = false, length = 100)
    private String name;

    @Column(nullable = false, unique = true)
    private String email;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    @Builder.Default
    private UserRole role = UserRole.MEMBER;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "organization_id", nullable = false)
    private Organization organization;

    @OneToMany(mappedBy = "author", cascade = CascadeType.ALL, orphanRemoval = true)
    @Builder.Default
    private Set<Post> posts = new HashSet<>();

    // Rich domain method — not a plain setter
    public void addPost(Post post) {
        posts.add(post);
        post.setAuthor(this);
    }
}

@Repository
public interface UserRepository extends JpaRepository<User, UUID>,
        JpaSpecificationExecutor<User> {
    Optional<User> findByEmail(String email);
    boolean existsByEmailAndOrganizationId(String email, UUID orgId);

    @Query("SELECT u FROM User u WHERE u.organization.id = :orgId AND u.active = true")
    Page<User> findActiveByOrganization(@Param("orgId") UUID orgId, Pageable pageable);

    @Modifying
    @Query("UPDATE User u SET u.active = false WHERE u.id = :id")
    void deactivate(@Param("id") UUID id);
}

public class UserSpecification {
    public static Specification<User> inOrganization(UUID orgId) {
        return (root, q, cb) -> cb.equal(root.get("organization").get("id"), orgId);
    }
    public static Specification<User> isActive(boolean active) {
        return (root, q, cb) -> cb.equal(root.get("active"), active);
    }
}

@Service
@RequiredArgsConstructor
@Slf4j
@Transactional(readOnly = true)   // default for all methods
public class UserServiceImpl implements UserService {
    private final UserRepository userRepository;
    private final UserMapper userMapper;

    @Override
    @Transactional   // override for writes
    public UserResponse create(CreateUserRequest req, UUID orgId) {
        if (userRepository.existsByEmailAndOrganizationId(req.email(), orgId)) {
            throw new BusinessException("Email already exists");
        }
        var user = User.builder()
            .name(req.name())
            .email(req.email().toLowerCase())
            .organization(orgRepository.findById(orgId)
                .orElseThrow(() -> new ResourceNotFoundException("Organization", orgId)))
            .build();
        return userMapper.toResponse(userRepository.save(user));
    }
}

@RestControllerAdvice
@Slf4j
public class GlobalExceptionHandler {
    @ExceptionHandler(ResourceNotFoundException.class)
    public ProblemDetail handleNotFound(ResourceNotFoundException ex) {
        var pd = ProblemDetail.forStatusAndDetail(HttpStatus.NOT_FOUND, ex.getMessage());
        pd.setProperty("timestamp", Instant.now());
        return pd;
    }
    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ProblemDetail handleValidation(MethodArgumentNotValidException ex) {
        var errors = new HashMap<String, String>();
        ex.getBindingResult().getFieldErrors()
            .forEach(e -> errors.put(e.getField(), e.getDefaultMessage()));
        var pd = ProblemDetail.forStatusAndDetail(HttpStatus.BAD_REQUEST, "Validation failed");
        pd.setProperty("errors", errors);
        pd.setProperty("timestamp", Instant.now());
        return pd;
    }
}
